mapper.select:
SELECT k.id, k.title, k.summary, k.category_id, c.name AS category_name,
       k.view_count, k.is_vectorized, k.created_at, k.updated_at
FROM knowledge k
LEFT JOIN category c ON k.category_id = c.id AND c.deleted = 0

    INNER JOIN knowledge_tag kt ON k.id = kt.knowledge_id AND kt.tag_id = #{tagId}

WHERE k.deleted = 0

    AND k.user_id = #{userId}


    AND k.category_id = #{categoryId}

ORDER BY k.updated_at DESC

SELECT k.id, k.title, k.summary, k.category_id, k.view_count, k.is_vectorized, k.created_at, k.updated_at, MATCH(k.title, k.content) AGAINST (#{keyword} IN BOOLEAN MODE) AS score FROM knowledge k WHERE k.deleted = 0 AND MATCH(k.title, k.content) AGAINST (#{keyword} IN BOOLEAN MODE)
AND k.user_id = #{userId}
ORDER BY score DESC LIMIT 20
